/* a+ core 2 :: content/questions4.js — Domain 4 Operational Procedures (220-1202). */
window.APLUS2 = window.APLUS2 || {};
APLUS2.questions = APLUS2.questions || [];
APLUS2.questions.push(
{ id:"D4-001", domain:4, obj:"4.1", diff:"easy", q:"A help desk uses a system to log, track, and prioritize user-reported problems from creation through resolution. What is this system called?", options:["A ticketing system","A knowledge base","An asset management database","A network topology diagram"], answer:0, explain:"<strong>A ticketing system</strong> is correct because it creates, tracks, prioritizes, and documents support issues through their full lifecycle.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A knowledge base</b>: stores reference articles and solutions, not active issue tracking.</span><span class='qd'><b>An asset management database</b>: tracks hardware/software inventory, not support requests.</span><span class='qd'><b>A network topology diagram</b>: maps network layout, not user issues.</span>" },
{ id:"D4-002", domain:4, obj:"4.1", diff:"easy", q:"Which document defines the acceptable ways employees may use company computers, networks, and internet access?", options:["SOP","Acceptable use policy (AUP)","Incident report","Knowledge base article"], answer:1, explain:"<strong>Acceptable use policy (AUP)</strong> is correct because it spells out permitted and prohibited uses of organizational IT resources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SOP</b>: describes how to perform a task step by step, not usage rules.</span><span class='qd'><b>Incident report</b>: documents a specific event after it occurs.</span><span class='qd'><b>Knowledge base article</b>: provides troubleshooting reference, not policy.</span>" },
{ id:"D4-003", domain:4, obj:"4.1", diff:"easy", q:"A technician needs the step-by-step instructions the company requires for imaging a new laptop. Which document should they consult?", options:["AUP","Network topology diagram","Standard operating procedure (SOP)","Incident report"], answer:2, explain:"<strong>Standard operating procedure (SOP)</strong> is correct because an SOP provides the documented, repeatable steps for performing a routine task.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AUP</b>: governs acceptable use, not task steps.</span><span class='qd'><b>Network topology diagram</b>: shows network layout, not procedures.</span><span class='qd'><b>Incident report</b>: records a specific event.</span>" },
{ id:"D4-004", domain:4, obj:"4.1", diff:"medium", q:"An organization wants a centralized repository where technicians and users can search articles for solutions to common problems. Which resource best fits?", options:["Ticketing system","Knowledge base","Asset tags","Splash screen"], answer:1, explain:"<strong>Knowledge base</strong> is correct because it is a searchable repository of articles and documented solutions for common issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ticketing system</b>: tracks individual incidents, not a knowledge library.</span><span class='qd'><b>Asset tags</b>: identify physical equipment.</span><span class='qd'><b>Splash screen</b>: a startup notice, not a solution repository.</span>" },
{ id:"D4-005", domain:4, obj:"4.1", diff:"medium", q:"A diagram shows how switches, routers, servers, and workstations physically and logically connect across a building. What is this diagram called?", options:["Asset map","Network topology diagram","Incident report","Compliance matrix"], answer:1, explain:"<strong>Network topology diagram</strong> is correct because it documents how network devices connect and communicate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asset map</b>: not a standard CompTIA document for connectivity.</span><span class='qd'><b>Incident report</b>: documents an event.</span><span class='qd'><b>Compliance matrix</b>: maps controls to regulations, not network layout.</span>" },
{ id:"D4-006", domain:4, obj:"4.1", diff:"medium", q:"What is the primary purpose of attaching a barcoded asset tag to a company laptop?", options:["To prevent malware infection","To track and inventory the device in asset management","To encrypt the drive","To display a legal warning at boot"], answer:1, explain:"<strong>To track and inventory the device in asset management</strong> is correct because asset tags uniquely identify equipment for inventory, auditing, and lifecycle tracking.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To prevent malware infection</b>: tags have no security software function.</span><span class='qd'><b>To encrypt the drive</b>: encryption is a software/firmware function.</span><span class='qd'><b>To display a legal warning at boot</b>: that is a splash screen function.</span>" },
{ id:"D4-007", domain:4, obj:"4.1", diff:"medium", q:"A login screen displays a message stating that the system is for authorized use only and activity may be monitored. What is this called?", options:["Splash screen / login banner","Knowledge base article","Incident report","SOP"], answer:0, explain:"<strong>Splash screen / login banner</strong> is correct because it is a startup or login notice that communicates authorized-use and monitoring statements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Knowledge base article</b>: a troubleshooting reference.</span><span class='qd'><b>Incident report</b>: documents an event after the fact.</span><span class='qd'><b>SOP</b>: documents task steps.</span>" },
{ id:"D4-008", domain:4, obj:"4.1", diff:"hard", q:"During a security event, a technician must record exactly what happened, when, who was involved, and the actions taken. Which document captures this?", options:["AUP","Incident report","SOP","Network topology diagram"], answer:1, explain:"<strong>Incident report</strong> is correct because it formally documents the details, timeline, and response of a specific event for review and accountability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AUP</b>: states acceptable use rules.</span><span class='qd'><b>SOP</b>: documents routine procedures.</span><span class='qd'><b>Network topology diagram</b>: shows network layout.</span>" },
{ id:"D4-009", domain:4, obj:"4.1", diff:"hard", q:"A healthcare clinic must follow rules governing how patient data is handled. Which documentation concern does this represent?", options:["Splash screens","Regulatory compliance requirements","Asset tagging","Knowledge base articles"], answer:1, explain:"<strong>Regulatory compliance requirements</strong> is correct because handling patient data is governed by external regulations the organization must document and follow.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Splash screens</b>: are boot/login notices.</span><span class='qd'><b>Asset tagging</b>: tracks equipment inventory.</span><span class='qd'><b>Knowledge base articles</b>: provide troubleshooting reference.</span>" },
{ id:"D4-010", domain:4, obj:"4.1", diff:"hard", q:"A technician resolves a recurring printer error and wants to ensure future technicians can fix it quickly. What is the best action?", options:["Delete the ticket once closed","Write a knowledge base article documenting the fix","Update the AUP","Re-image the printer's firmware"], answer:1, explain:"<strong>Write a knowledge base article documenting the fix</strong> is correct because adding the solution to the KB makes it searchable and reusable by others.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete the ticket once closed</b>: removes valuable history.</span><span class='qd'><b>Update the AUP</b>: usage policy is unrelated to a technical fix.</span><span class='qd'><b>Re-image the printer's firmware</b>: does not document the solution for reuse.</span>" },
{ id:"D4-011", domain:4, obj:"4.1", diff:"easy", q:"Which field in a support ticket helps technicians decide which issues to work on first?", options:["Priority/severity","Asset tag color","Splash screen text","License key"], answer:0, explain:"<strong>Priority/severity</strong> is correct because it indicates urgency and impact so technicians can triage and order their work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asset tag color</b>: not a triage field.</span><span class='qd'><b>Splash screen text</b>: unrelated to ticket handling.</span><span class='qd'><b>License key</b>: relates to software, not triage.</span>" },
{ id:"D4-012", domain:4, obj:"4.1", diff:"medium", q:"Which item would typically be tracked in an asset management database?", options:["A list of forbidden websites","Hardware serial numbers, purchase dates, and warranty status","Active support ticket queues","Daily backup logs"], answer:1, explain:"<strong>Hardware serial numbers, purchase dates, and warranty status</strong> is correct because asset management records equipment identity and lifecycle data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A list of forbidden websites</b>: belongs in an AUP or web filter.</span><span class='qd'><b>Active support ticket queues</b>: belong to the ticketing system.</span><span class='qd'><b>Daily backup logs</b>: belong to backup systems.</span>" },
{ id:"D4-013", domain:4, obj:"4.1", diff:"easy", q:"What is the main benefit of recording detailed notes in a support ticket as work progresses?", options:["It speeds up the CPU","It creates a clear history for handoffs, audits, and future reference","It encrypts the user's files","It updates the network topology automatically"], answer:1, explain:"<strong>It creates a clear history for handoffs, audits, and future reference</strong> is correct because documented progress preserves context and accountability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It speeds up the CPU</b>: notes have no performance effect.</span><span class='qd'><b>It encrypts the user's files</b>: documentation is not encryption.</span><span class='qd'><b>It updates the network topology automatically</b>: unrelated function.</span>" },
{ id:"D4-014", domain:4, obj:"4.1", diff:"medium", q:"A new technician needs to understand how the company expects backups to be performed daily. Which document is the best source?", options:["Incident report","Standard operating procedure (SOP)","Network topology diagram","Asset tag log"], answer:1, explain:"<strong>Standard operating procedure (SOP)</strong> is correct because it documents the step-by-step routine the company follows for recurring tasks like backups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incident report</b>: documents specific events.</span><span class='qd'><b>Network topology diagram</b>: shows connectivity.</span><span class='qd'><b>Asset tag log</b>: tracks equipment, not procedures.</span>" },
{ id:"D4-015", domain:4, obj:"4.1", diff:"hard", q:"An auditor asks the IT department to prove which employees agreed to the rules on company internet use. Which document and record should IT provide?", options:["The network topology diagram and ping logs","The signed acceptable use policy (AUP) acknowledgements","The knowledge base index","The backup verification report"], answer:1, explain:"<strong>The signed acceptable use policy (AUP) acknowledgements</strong> is correct because signed AUP records prove employees accepted the usage rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The network topology diagram and ping logs</b>: relate to connectivity, not policy acceptance.</span><span class='qd'><b>The knowledge base index</b>: lists articles, not acknowledgements.</span><span class='qd'><b>The backup verification report</b>: relates to data protection.</span>" },
{ id:"D4-016", domain:4, obj:"4.1", diff:"medium", q:"Which documentation would most help a technician quickly locate which switch a malfunctioning workstation connects to?", options:["Incident report","AUP","Network topology diagram","Knowledge base article"], answer:2, explain:"<strong>Network topology diagram</strong> is correct because it maps device connections, helping trace a workstation to its switch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incident report</b>: documents events.</span><span class='qd'><b>AUP</b>: states usage rules.</span><span class='qd'><b>Knowledge base article</b>: provides troubleshooting steps.</span>" },
{ id:"D4-017", domain:4, obj:"4.1", diff:"easy", q:"Regulatory compliance documentation is primarily concerned with ensuring an organization:", options:["Has the fastest possible network","Meets legal and industry standards for handling data and operations","Uses only open-source software","Disables all splash screens"], answer:1, explain:"<strong>Meets legal and industry standards for handling data and operations</strong> is correct because compliance ensures adherence to external laws and standards.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Has the fastest possible network</b>: speed is not compliance.</span><span class='qd'><b>Uses only open-source software</b>: licensing choice is unrelated.</span><span class='qd'><b>Disables all splash screens</b>: irrelevant to compliance goals.</span>" },
{ id:"D4-018", domain:4, obj:"4.1", diff:"hard", q:"A company wants to reduce repeat tickets for the same Wi-Fi setup question. Which combination best addresses this?", options:["Delete old tickets and disable the ticketing system","Publish a knowledge base article and link it in ticket auto-responses","Replace the AUP with a splash screen","Re-tag all assets"], answer:1, explain:"<strong>Publish a knowledge base article and link it in ticket auto-responses</strong> is correct because self-service KB content deflects repetitive tickets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete old tickets and disable the ticketing system</b>: destroys history and tracking.</span><span class='qd'><b>Replace the AUP with a splash screen</b>: unrelated to deflecting questions.</span><span class='qd'><b>Re-tag all assets</b>: inventory work, not knowledge sharing.</span>" },
{ id:"D4-019", domain:4, obj:"4.1", diff:"medium", q:"Which of the following is the BEST description of a standard operating procedure?", options:["A legally binding contract with a vendor","A documented set of steps to consistently perform a routine task","A list of all company assets","A record of a single security breach"], answer:1, explain:"<strong>A documented set of steps to consistently perform a routine task</strong> is correct because SOPs standardize how recurring work is done.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A legally binding contract with a vendor</b>: that is a contract/SLA.</span><span class='qd'><b>A list of all company assets</b>: that is an asset inventory.</span><span class='qd'><b>A record of a single security breach</b>: that is an incident report.</span>" },
{ id:"D4-020", domain:4, obj:"4.1", diff:"hard", q:"A technician notices the company stores PII but has no documented process for who can access it or how. Which documentation gap should be raised first?", options:["Missing splash screen","Missing regulatory compliance and SOP documentation for data handling","Missing network topology diagram","Missing asset tags"], answer:1, explain:"<strong>Missing regulatory compliance and SOP documentation for data handling</strong> is correct because PII handling requires documented procedures and compliance with regulations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Missing splash screen</b>: a minor notice, not a data-handling control.</span><span class='qd'><b>Missing network topology diagram</b>: about connectivity, not data access.</span><span class='qd'><b>Missing asset tags</b>: about equipment inventory.</span>" },
{ id:"D4-021", domain:4, obj:"4.2", diff:"easy", q:"In change management, what is the purpose of a rollback plan?", options:["To delete the change permanently","To restore systems to their previous state if the change fails","To approve the change","To test the change in a sandbox"], answer:1, explain:"<strong>To restore systems to their previous state if the change fails</strong> is correct because a rollback plan defines how to revert when a change causes problems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To delete the change permanently</b>: rollback reverts, it does not erase records.</span><span class='qd'><b>To approve the change</b>: that is the change board's role.</span><span class='qd'><b>To test the change in a sandbox</b>: that is sandbox testing, a separate step.</span>" },
{ id:"D4-022", domain:4, obj:"4.2", diff:"easy", q:"Which group typically reviews and authorizes proposed changes before they are implemented?", options:["The change advisory board (change board)","The help desk queue","The end users","The backup operators"], answer:0, explain:"<strong>The change advisory board (change board)</strong> is correct because it evaluates and approves changes to control risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The help desk queue</b>: handles support tickets, not approvals.</span><span class='qd'><b>The end users</b>: provide acceptance but do not authorize.</span><span class='qd'><b>The backup operators</b>: manage backups, not change approval.</span>" },
{ id:"D4-023", domain:4, obj:"4.2", diff:"easy", q:"Before deploying a change widely, a technician tests it in an isolated environment that mirrors production. What is this environment called?", options:["A rollback plan","A sandbox","A change board","A splash screen"], answer:1, explain:"<strong>A sandbox</strong> is correct because it is an isolated test environment used to validate changes safely.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A rollback plan</b>: is the revert strategy, not an environment.</span><span class='qd'><b>A change board</b>: is a group that approves changes.</span><span class='qd'><b>A splash screen</b>: is a startup notice.</span>" },
{ id:"D4-024", domain:4, obj:"4.2", diff:"medium", q:"What does the risk analysis portion of a change request primarily identify?", options:["The cost of new hardware only","The potential negative impacts and likelihood of the change causing problems","The end users' job titles","The color of the asset tags"], answer:1, explain:"<strong>The potential negative impacts and likelihood of the change causing problems</strong> is correct because risk analysis weighs what could go wrong and how likely it is.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The cost of new hardware only</b>: cost is just one factor, not the focus.</span><span class='qd'><b>The end users' job titles</b>: irrelevant to risk.</span><span class='qd'><b>The color of the asset tags</b>: unrelated.</span>" },
{ id:"D4-025", domain:4, obj:"4.2", diff:"medium", q:"Why does a change request form typically include a clearly defined scope of the change?", options:["To make the request longer","To define exactly what is and is not affected so impact can be assessed","To bypass the change board","To replace the rollback plan"], answer:1, explain:"<strong>To define exactly what is and is not affected so impact can be assessed</strong> is correct because scope bounds the change and clarifies affected systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make the request longer</b>: length is not the goal.</span><span class='qd'><b>To bypass the change board</b>: scope informs the board, not bypasses it.</span><span class='qd'><b>To replace the rollback plan</b>: scope and rollback are separate elements.</span>" },
{ id:"D4-026", domain:4, obj:"4.2", diff:"medium", q:"After a change is deployed, users confirm the system works as expected for their workflows. Which change management step is this?", options:["Risk analysis","End-user acceptance","Sandbox testing","Rollback"], answer:1, explain:"<strong>End-user acceptance</strong> is correct because it is the step where users verify the change meets their needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk analysis</b>: happens before implementation.</span><span class='qd'><b>Sandbox testing</b>: occurs in an isolated environment, not by end users.</span><span class='qd'><b>Rollback</b>: reverts a failed change.</span>" },
{ id:"D4-027", domain:4, obj:"4.2", diff:"hard", q:"A proposed firewall update could disrupt critical services. The change board asks what will happen if it fails. Which document directly answers this?", options:["The scope statement","The rollback plan","The asset inventory","The AUP"], answer:1, explain:"<strong>The rollback plan</strong> is correct because it specifies how to revert if the change fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The scope statement</b>: defines what is affected, not recovery steps.</span><span class='qd'><b>The asset inventory</b>: lists equipment.</span><span class='qd'><b>The AUP</b>: states acceptable use rules.</span>" },
{ id:"D4-028", domain:4, obj:"4.2", diff:"hard", q:"Which best explains the value of documenting business processes affected by a change?", options:["It guarantees the change board will approve it","It clarifies how the change impacts day-to-day operations and dependencies","It eliminates the need for a rollback plan","It encrypts the affected systems"], answer:1, explain:"<strong>It clarifies how the change impacts day-to-day operations and dependencies</strong> is correct because documented processes reveal what the change touches operationally.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the change board will approve it</b>: documentation informs, it does not guarantee approval.</span><span class='qd'><b>It eliminates the need for a rollback plan</b>: rollback is still required.</span><span class='qd'><b>It encrypts the affected systems</b>: unrelated function.</span>" },
{ id:"D4-029", domain:4, obj:"4.2", diff:"medium", q:"What is the main reason changes should follow a formal request process rather than being applied ad hoc?", options:["To slow down all work","To ensure changes are reviewed, approved, documented, and reversible","To avoid using a sandbox","To remove end users from the process"], answer:1, explain:"<strong>To ensure changes are reviewed, approved, documented, and reversible</strong> is correct because formal change management reduces risk and maintains accountability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To slow down all work</b>: control, not delay, is the goal.</span><span class='qd'><b>To avoid using a sandbox</b>: sandboxes are encouraged.</span><span class='qd'><b>To remove end users from the process</b>: user acceptance is part of it.</span>" },
{ id:"D4-030", domain:4, obj:"4.2", diff:"easy", q:"A change request form's purpose-of-change field is used to:", options:["Record why the change is needed and its expected benefit","List the technician's lunch schedule","Store the BIOS password","Track printer toner levels"], answer:0, explain:"<strong>Record why the change is needed and its expected benefit</strong> is correct because the purpose justifies the change to reviewers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>List the technician's lunch schedule</b>: irrelevant.</span><span class='qd'><b>Store the BIOS password</b>: a security setting, not a change purpose.</span><span class='qd'><b>Track printer toner levels</b>: unrelated.</span>" },
{ id:"D4-031", domain:4, obj:"4.2", diff:"hard", q:"A technician tests a major OS patch in a sandbox, but skips updating the rollback plan because the sandbox test passed. What is the risk?", options:["The sandbox will overheat","If the production deployment fails, there is no documented way to revert","End users will gain admin rights","The change board will be disbanded"], answer:1, explain:"<strong>If the production deployment fails, there is no documented way to revert</strong> is correct because successful sandbox testing does not guarantee production success, so a rollback plan is still essential.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The sandbox will overheat</b>: not a meaningful risk.</span><span class='qd'><b>End users will gain admin rights</b>: unrelated to skipping rollback.</span><span class='qd'><b>The change board will be disbanded</b>: not a consequence.</span>" },
{ id:"D4-032", domain:4, obj:"4.2", diff:"medium", q:"Which item is typically NOT part of a formal change request?", options:["Purpose and scope of the change","Risk analysis","Rollback plan","The end user's home address"], answer:3, explain:"<strong>The end user's home address</strong> is correct because personal addresses are not part of a change request.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Purpose and scope of the change</b>: required to justify and bound the change.</span><span class='qd'><b>Risk analysis</b>: required to assess impact.</span><span class='qd'><b>Rollback plan</b>: required for recovery.</span>" },
{ id:"D4-033", domain:4, obj:"4.2", diff:"easy", q:"What does change management primarily aim to reduce?", options:["The number of employees","Unplanned disruptions and risk from modifications","Electricity costs","Software licensing fees"], answer:1, explain:"<strong>Unplanned disruptions and risk from modifications</strong> is correct because change management controls how changes are introduced to minimize disruption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The number of employees</b>: not a change management goal.</span><span class='qd'><b>Electricity costs</b>: unrelated.</span><span class='qd'><b>Software licensing fees</b>: not the focus.</span>" },
{ id:"D4-034", domain:4, obj:"4.2", diff:"hard", q:"During risk analysis for a server migration, the team rates both the probability and the business impact of failure. What is the BEST use of these ratings?", options:["To prioritize and decide whether and how to proceed with mitigations","To set the asset tag numbers","To choose a splash screen message","To determine the AUP wording"], answer:0, explain:"<strong>To prioritize and decide whether and how to proceed with mitigations</strong> is correct because probability and impact ratings guide go/no-go decisions and mitigation planning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To set the asset tag numbers</b>: unrelated.</span><span class='qd'><b>To choose a splash screen message</b>: irrelevant.</span><span class='qd'><b>To determine the AUP wording</b>: policy is separate.</span>" },
{ id:"D4-035", domain:4, obj:"4.2", diff:"medium", q:"A change was implemented but caused critical errors. The technician follows documented steps to return the environment to its prior working state. What did they execute?", options:["Sandbox test","Rollback plan","Risk analysis","Change request form"], answer:1, explain:"<strong>Rollback plan</strong> is correct because reverting to the prior working state is the rollback action.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sandbox test</b>: occurs before deployment.</span><span class='qd'><b>Risk analysis</b>: assesses risk beforehand.</span><span class='qd'><b>Change request form</b>: initiates the change.</span>" },
{ id:"D4-036", domain:4, obj:"4.2", diff:"medium", q:"Why is end-user acceptance an important final step in many change processes?", options:["It lets users approve the budget","It confirms the change actually works for those who use the system daily","It replaces the need for documentation","It assigns asset tags"], answer:1, explain:"<strong>It confirms the change actually works for those who use the system daily</strong> is correct because user acceptance validates real-world functionality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It lets users approve the budget</b>: budgeting is separate.</span><span class='qd'><b>It replaces the need for documentation</b>: documentation is still required.</span><span class='qd'><b>It assigns asset tags</b>: unrelated.</span>" },
{ id:"D4-037", domain:4, obj:"4.2", diff:"hard", q:"A company applies emergency changes directly to production without sandbox testing or board approval. Which is the MOST significant long-term risk?", options:["Slower internet speeds","Unvetted changes increasing the chance of outages and unmanaged risk","Higher toner usage","Loss of asset tags"], answer:1, explain:"<strong>Unvetted changes increasing the chance of outages and unmanaged risk</strong> is correct because skipping testing and approval removes the controls that prevent damaging changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slower internet speeds</b>: not a direct result.</span><span class='qd'><b>Higher toner usage</b>: unrelated.</span><span class='qd'><b>Loss of asset tags</b>: unrelated.</span>" },
{ id:"D4-038", domain:4, obj:"4.2", diff:"easy", q:"Which document initiates the change management workflow by formally proposing a modification?", options:["Incident report","Change request form","Knowledge base article","Backup log"], answer:1, explain:"<strong>Change request form</strong> is correct because it formally proposes and documents the desired change to start the process.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incident report</b>: documents an event.</span><span class='qd'><b>Knowledge base article</b>: provides reference solutions.</span><span class='qd'><b>Backup log</b>: records backup activity.</span>" },
{ id:"D4-039", domain:4, obj:"4.2", diff:"medium", q:"What is the relationship between sandbox testing and risk analysis in change management?", options:["They are the same thing","Sandbox testing validates the change in isolation, while risk analysis evaluates potential impacts","Risk analysis replaces the need for sandbox testing","Sandbox testing only happens after end-user acceptance"], answer:1, explain:"<strong>Sandbox testing validates the change in isolation, while risk analysis evaluates potential impacts</strong> is correct because they are complementary: one tests, the other assesses risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are the same thing</b>: they serve different functions.</span><span class='qd'><b>Risk analysis replaces the need for sandbox testing</b>: both are valuable.</span><span class='qd'><b>Sandbox testing only happens after end-user acceptance</b>: testing precedes deployment and acceptance.</span>" },
{ id:"D4-040", domain:4, obj:"4.2", diff:"hard", q:"The change board rejects a request because the rollback plan is missing. What does this enforce about good change management?", options:["Changes must always be permanent","Every change should have a defined way to recover if it fails","End users must write all changes","Sandboxes are unnecessary"], answer:1, explain:"<strong>Every change should have a defined way to recover if it fails</strong> is correct because requiring a rollback plan ensures recoverability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Changes must always be permanent</b>: the opposite is true.</span><span class='qd'><b>End users must write all changes</b>: not a requirement.</span><span class='qd'><b>Sandboxes are unnecessary</b>: sandboxes remain valuable.</span>" },
{ id:"D4-041", domain:4, obj:"4.3", diff:"easy", q:"Which backup type copies all selected data every time it runs, regardless of prior backups?", options:["Incremental","Differential","Full","Synthetic"], answer:2, explain:"<strong>Full</strong> is correct because a full backup captures all selected data each time it runs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incremental</b>: copies only data changed since the last backup.</span><span class='qd'><b>Differential</b>: copies data changed since the last full backup.</span><span class='qd'><b>Synthetic</b>: combines a full and subsequent backups into a new full without re-reading all source data.</span>" },
{ id:"D4-042", domain:4, obj:"4.3", diff:"easy", q:"Which backup type copies only the data that has changed since the last backup of any type?", options:["Full","Incremental","Differential","Synthetic full"], answer:1, explain:"<strong>Incremental</strong> is correct because it backs up only data changed since the most recent backup, making it fast and space-efficient.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full</b>: copies everything each time.</span><span class='qd'><b>Differential</b>: copies all changes since the last full backup.</span><span class='qd'><b>Synthetic full</b>: assembled from existing backups.</span>" },
{ id:"D4-043", domain:4, obj:"4.3", diff:"medium", q:"Which backup type copies all data changed since the last FULL backup, growing larger until the next full?", options:["Incremental","Differential","Synthetic","Image-level"], answer:1, explain:"<strong>Differential</strong> is correct because each differential backup captures everything changed since the last full backup, so it grows over time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incremental</b>: captures changes since the last backup of any type.</span><span class='qd'><b>Synthetic</b>: a constructed full backup.</span><span class='qd'><b>Image-level</b>: describes the scope (whole disk), not the change-tracking method.</span>" },
{ id:"D4-044", domain:4, obj:"4.3", diff:"easy", q:"The 3-2-1 backup rule recommends keeping how many total copies of data?", options:["1","2","3","6"], answer:2, explain:"<strong>3</strong> is correct because the 3-2-1 rule says keep 3 copies of data, on 2 different media types, with 1 copy off-site.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>1</b>: that is a single copy, no redundancy.</span><span class='qd'><b>2</b>: matches the media types, not total copies.</span><span class='qd'><b>6</b>: not part of the rule.</span>" },
{ id:"D4-045", domain:4, obj:"4.3", diff:"medium", q:"In the 3-2-1 backup rule, the '1' refers to:", options:["One copy stored off-site","One full backup per year","One backup media type","One backup test"], answer:0, explain:"<strong>One copy stored off-site</strong> is correct because the rule keeps at least one of the three copies off-site for disaster protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One full backup per year</b>: not part of the rule.</span><span class='qd'><b>One backup media type</b>: the rule specifies two media types.</span><span class='qd'><b>One backup test</b>: testing is separate from the 3-2-1 rule.</span>" },
{ id:"D4-046", domain:4, obj:"4.3", diff:"medium", q:"A synthetic full backup is created by:", options:["Re-reading all source files from production","Combining an existing full backup with subsequent incremental backups","Copying only changes since the last full","Imaging the entire disk sector by sector"], answer:1, explain:"<strong>Combining an existing full backup with subsequent incremental backups</strong> is correct because a synthetic full is assembled from existing backups without re-reading all source data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Re-reading all source files from production</b>: that is a traditional full backup.</span><span class='qd'><b>Copying only changes since the last full</b>: that is a differential.</span><span class='qd'><b>Imaging the entire disk sector by sector</b>: that is image-level backup.</span>" },
{ id:"D4-047", domain:4, obj:"4.3", diff:"medium", q:"What is the key difference between image-level and file-level backups?", options:["Image-level captures an entire drive/system state; file-level captures selected files and folders","File-level is always faster to restore an entire OS","Image-level cannot be stored off-site","File-level requires a synthetic full"], answer:0, explain:"<strong>Image-level captures an entire drive/system state; file-level captures selected files and folders</strong> is correct because image backups are bare-metal-capable while file backups target specific data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>File-level is always faster to restore an entire OS</b>: image-level is better for full system restores.</span><span class='qd'><b>Image-level cannot be stored off-site</b>: it can be stored anywhere.</span><span class='qd'><b>File-level requires a synthetic full</b>: not a requirement.</span>" },
{ id:"D4-048", domain:4, obj:"4.3", diff:"hard", q:"Grandfather-father-son (GFS) rotation primarily organizes backups by:", options:["File size","Retention tiers such as daily, weekly, and monthly sets","Network speed","Encryption strength"], answer:1, explain:"<strong>Retention tiers such as daily, weekly, and monthly sets</strong> is correct because GFS rotates media across daily (son), weekly (father), and monthly (grandfather) retention levels.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>File size</b>: GFS is about retention, not size.</span><span class='qd'><b>Network speed</b>: unrelated.</span><span class='qd'><b>Encryption strength</b>: unrelated to rotation scheme.</span>" },
{ id:"D4-049", domain:4, obj:"4.3", diff:"hard", q:"Why is regularly testing and verifying backups critical even if backups complete without error?", options:["It frees up CPU cycles","A backup that completes may still be corrupt or unrestorable, so verification proves recoverability","It increases internet bandwidth","It removes the need for off-site copies"], answer:1, explain:"<strong>A backup that completes may still be corrupt or unrestorable, so verification proves recoverability</strong> is correct because only a tested restore confirms the data is usable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It frees up CPU cycles</b>: not the purpose.</span><span class='qd'><b>It increases internet bandwidth</b>: unrelated.</span><span class='qd'><b>It removes the need for off-site copies</b>: off-site storage is still recommended.</span>" },
{ id:"D4-050", domain:4, obj:"4.3", diff:"medium", q:"What is a key advantage of storing a backup copy off-site rather than only on-site?", options:["Faster daily backups","Protection against site-wide disasters like fire or flood","No need to encrypt data","Lower licensing costs"], answer:1, explain:"<strong>Protection against site-wide disasters like fire or flood</strong> is correct because off-site copies survive events that destroy the primary location.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Faster daily backups</b>: on-site is usually faster.</span><span class='qd'><b>No need to encrypt data</b>: off-site data often needs more encryption.</span><span class='qd'><b>Lower licensing costs</b>: unrelated.</span>" },
{ id:"D4-051", domain:4, obj:"4.3", diff:"hard", q:"A restore from incremental backups requires which sets?", options:["Only the most recent incremental","The last full backup plus every incremental since that full, in order","The last full plus the latest incremental only","Any single incremental backup"], answer:1, explain:"<strong>The last full backup plus every incremental since that full, in order</strong> is correct because incrementals only contain changes since the prior backup, so the full and all subsequent increments are needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the most recent incremental</b>: it lacks earlier changes.</span><span class='qd'><b>The last full plus the latest incremental only</b>: that describes differential restores.</span><span class='qd'><b>Any single incremental backup</b>: insufficient on its own.</span>" },
{ id:"D4-052", domain:4, obj:"4.3", diff:"hard", q:"A restore from differential backups requires which sets?", options:["The last full backup plus all differentials","The last full backup plus only the most recent differential","Only the most recent differential","Every incremental since the full"], answer:1, explain:"<strong>The last full backup plus only the most recent differential</strong> is correct because each differential contains all changes since the last full, so only the newest one is needed with the full.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The last full backup plus all differentials</b>: only the latest differential is required.</span><span class='qd'><b>Only the most recent differential</b>: the full is also required.</span><span class='qd'><b>Every incremental since the full</b>: that is the incremental restore method.</span>" },
{ id:"D4-053", domain:4, obj:"4.3", diff:"easy", q:"Which backup approach generally uses the LEAST storage per backup job?", options:["Full","Incremental","Differential","Synthetic full"], answer:1, explain:"<strong>Incremental</strong> is correct because it stores only the changes since the last backup, minimizing per-job size.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full</b>: copies everything, the largest.</span><span class='qd'><b>Differential</b>: grows larger over time since the last full.</span><span class='qd'><b>Synthetic full</b>: a full-size constructed backup.</span>" },
{ id:"D4-054", domain:4, obj:"4.3", diff:"medium", q:"In the 3-2-1 rule, the '2' refers to:", options:["Two off-site locations","Two different storage media types","Two backup tests","Two backup operators"], answer:1, explain:"<strong>Two different storage media types</strong> is correct because the rule recommends storing copies on two distinct media to avoid a single point of failure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Two off-site locations</b>: the rule specifies one off-site copy.</span><span class='qd'><b>Two backup tests</b>: not part of the rule.</span><span class='qd'><b>Two backup operators</b>: unrelated.</span>" },
{ id:"D4-055", domain:4, obj:"4.3", diff:"hard", q:"A company restores a server from an image-level backup after a drive failure. What is the MAIN benefit of image-level over file-level here?", options:["It restores only selected documents","It restores the entire system state including OS, apps, and settings for bare-metal recovery","It uses less storage than file-level","It does not require the original full backup"], answer:1, explain:"<strong>It restores the entire system state including OS, apps, and settings for bare-metal recovery</strong> is correct because image backups enable complete system restoration after hardware failure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It restores only selected documents</b>: that is file-level.</span><span class='qd'><b>It uses less storage than file-level</b>: images are usually larger.</span><span class='qd'><b>It does not require the original full backup</b>: the image itself is the full source.</span>" },
{ id:"D4-056", domain:4, obj:"4.3", diff:"medium", q:"A nightly job runs a full backup Sunday and incrementals Monday through Saturday. On Wednesday a file is lost. To restore Wednesday's version, which sets are needed?", options:["Sunday full only","Sunday full plus Monday, Tuesday, and Wednesday incrementals","Wednesday incremental only","Sunday full plus Wednesday incremental"], answer:1, explain:"<strong>Sunday full plus Monday, Tuesday, and Wednesday incrementals</strong> is correct because incrementals must be applied in sequence from the last full.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sunday full only</b>: lacks changes since Sunday.</span><span class='qd'><b>Wednesday incremental only</b>: lacks the base and prior days.</span><span class='qd'><b>Sunday full plus Wednesday incremental</b>: skips Monday and Tuesday changes.</span>" },
{ id:"D4-057", domain:4, obj:"4.3", diff:"easy", q:"What is the primary goal of a backup and recovery strategy?", options:["To speed up the network","To ensure data can be restored after loss, corruption, or disaster","To reduce software licenses","To improve display resolution"], answer:1, explain:"<strong>To ensure data can be restored after loss, corruption, or disaster</strong> is correct because recovery of data is the core purpose of backups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To speed up the network</b>: not the purpose.</span><span class='qd'><b>To reduce software licenses</b>: unrelated.</span><span class='qd'><b>To improve display resolution</b>: unrelated.</span>" },
{ id:"D4-058", domain:4, obj:"4.3", diff:"hard", q:"An organization keeps all three backup copies on the same on-site NAS. Which 3-2-1 principle is violated, and what is the risk?", options:["The '3' principle; too many copies waste space","The '2' and '1' principles; a single site disaster could destroy all copies","The synthetic principle; backups cannot be combined","The GFS principle; rotation is impossible"], answer:1, explain:"<strong>The '2' and '1' principles; a single site disaster could destroy all copies</strong> is correct because all copies share one medium and one location, defeating media diversity and off-site protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The '3' principle; too many copies waste space</b>: three copies is the recommendation.</span><span class='qd'><b>The synthetic principle; backups cannot be combined</b>: not a 3-2-1 element.</span><span class='qd'><b>The GFS principle; rotation is impossible</b>: GFS is a separate scheme.</span>" },
{ id:"D4-059", domain:4, obj:"4.3", diff:"medium", q:"Which backup verification practice provides the strongest assurance that data is recoverable?", options:["Checking that the backup job reported success","Performing a periodic test restore of the data","Counting the number of backup files","Renaming the backup set"], answer:1, explain:"<strong>Performing a periodic test restore of the data</strong> is correct because an actual restore proves the backup is valid and usable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Checking that the backup job reported success</b>: success does not guarantee a usable restore.</span><span class='qd'><b>Counting the number of backup files</b>: file count proves nothing about integrity.</span><span class='qd'><b>Renaming the backup set</b>: has no verification value.</span>" },
{ id:"D4-060", domain:4, obj:"4.3", diff:"medium", q:"In a GFS rotation, the 'grandfather' set typically represents which retention level?", options:["Hourly backups","Daily backups","Weekly backups","Monthly backups"], answer:3, explain:"<strong>Monthly backups</strong> is correct because in GFS the grandfather is the longest-retained monthly set, father is weekly, and son is daily.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hourly backups</b>: not part of standard GFS tiers.</span><span class='qd'><b>Daily backups</b>: those are the son.</span><span class='qd'><b>Weekly backups</b>: those are the father.</span>" },
{ id:"D4-061", domain:4, obj:"4.4", diff:"easy", q:"What is the primary purpose of an ESD wrist strap?", options:["To physically secure the technician to the workbench","To safely equalize static charge between the technician and the equipment","To provide power to the motherboard","To measure voltage"], answer:1, explain:"<strong>To safely equalize static charge between the technician and the equipment</strong> is correct because the strap dissipates static to prevent electrostatic discharge damage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To physically secure the technician to the workbench</b>: it is not a restraint.</span><span class='qd'><b>To provide power to the motherboard</b>: it carries no operating power.</span><span class='qd'><b>To measure voltage</b>: that is a multimeter.</span>" },
{ id:"D4-062", domain:4, obj:"4.4", diff:"easy", q:"Before lifting a heavy server, what is the correct technique to avoid injury?", options:["Bend at the waist and lift with your back","Lift with your legs while keeping your back straight","Twist while lifting to save time","Lift the heaviest part first with one hand"], answer:1, explain:"<strong>Lift with your legs while keeping your back straight</strong> is correct because using leg muscles and keeping the back straight prevents back injury.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bend at the waist and lift with your back</b>: strains the back.</span><span class='qd'><b>Twist while lifting to save time</b>: twisting under load causes injury.</span><span class='qd'><b>Lift the heaviest part first with one hand</b>: unbalanced and unsafe.</span>" },
{ id:"D4-063", domain:4, obj:"4.4", diff:"easy", q:"Which device should be used to extinguish an electrical fire?", options:["Class A water extinguisher","Class C (or ABC) extinguisher rated for electrical fires","A bucket of water","A damp cloth"], answer:1, explain:"<strong>Class C (or ABC) extinguisher rated for electrical fires</strong> is correct because Class C extinguishers use non-conductive agents safe for energized electrical equipment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Class A water extinguisher</b>: water conducts electricity and risks shock.</span><span class='qd'><b>A bucket of water</b>: dangerous on electrical fires.</span><span class='qd'><b>A damp cloth</b>: ineffective and unsafe.</span>" },
{ id:"D4-064", domain:4, obj:"4.4", diff:"medium", q:"Why should a technician remove rings, watches, and other jewelry before working inside a computer?", options:["To look more professional","To prevent accidental shorts, snagging, and scratches on components","To improve typing speed","To reduce static buildup only"], answer:1, explain:"<strong>To prevent accidental shorts, snagging, and scratches on components</strong> is correct because conductive jewelry can short circuits and catch on parts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To look more professional</b>: not a safety reason.</span><span class='qd'><b>To improve typing speed</b>: irrelevant.</span><span class='qd'><b>To reduce static buildup only</b>: jewelry is more a short/snag hazard than a static one.</span>" },
{ id:"D4-065", domain:4, obj:"4.4", diff:"medium", q:"When should a technician wear safety glasses or goggles?", options:["Only when soldering","When there is a risk of flying debris, dust, or chemical splashes","Only outdoors","Never, they reduce visibility"], answer:1, explain:"<strong>When there is a risk of flying debris, dust, or chemical splashes</strong> is correct because eye protection guards against particles and chemicals during many tasks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only when soldering</b>: many other tasks pose eye risks too.</span><span class='qd'><b>Only outdoors</b>: indoor tasks can also be hazardous.</span><span class='qd'><b>Never, they reduce visibility</b>: protection outweighs minor visibility concerns.</span>" },
{ id:"D4-066", domain:4, obj:"4.4", diff:"medium", q:"Why might a technician wear an air filtration mask when cleaning the inside of dusty computers or printers?", options:["To stay warm","To avoid inhaling dust, toner particles, and other airborne contaminants","To reduce static discharge","To improve hearing"], answer:1, explain:"<strong>To avoid inhaling dust, toner particles, and other airborne contaminants</strong> is correct because masks protect the respiratory system from harmful particulates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To stay warm</b>: not a function of the mask.</span><span class='qd'><b>To reduce static discharge</b>: masks do not affect ESD.</span><span class='qd'><b>To improve hearing</b>: unrelated.</span>" },
{ id:"D4-067", domain:4, obj:"4.4", diff:"hard", q:"How should old lithium-ion laptop batteries be disposed of?", options:["In normal household trash","Through an approved battery recycling or hazardous waste program","Burned to destroy the cells","Flushed with water down a drain"], answer:1, explain:"<strong>Through an approved battery recycling or hazardous waste program</strong> is correct because batteries contain toxic and hazardous materials requiring proper recycling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>In normal household trash</b>: illegal in many areas and environmentally harmful.</span><span class='qd'><b>Burned to destroy the cells</b>: fire and explosion hazard.</span><span class='qd'><b>Flushed with water down a drain</b>: contaminates water and is dangerous.</span>" },
{ id:"D4-068", domain:4, obj:"4.4", diff:"hard", q:"Why do CRT monitors require special disposal handling?", options:["They contain lead and can hold a dangerous electrical charge","They are made entirely of plastic","They contain no hazardous materials","They are too lightweight to recycle"], answer:0, explain:"<strong>They contain lead and can hold a dangerous electrical charge</strong> is correct because CRTs include leaded glass and capacitors that can retain charge, requiring hazardous-waste handling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are made entirely of plastic</b>: they contain leaded glass and metal.</span><span class='qd'><b>They contain no hazardous materials</b>: lead is hazardous.</span><span class='qd'><b>They are too lightweight to recycle</b>: CRTs are heavy and hazardous.</span>" },
{ id:"D4-069", domain:4, obj:"4.4", diff:"medium", q:"Used toner cartridges should be disposed of by:", options:["Throwing them in regular trash","Returning them to a manufacturer recycling program or approved e-waste handler","Emptying the toner outdoors","Rinsing them in a sink"], answer:1, explain:"<strong>Returning them to a manufacturer recycling program or approved e-waste handler</strong> is correct because toner is a fine powder and the cartridge should be recycled responsibly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Throwing them in regular trash</b>: wasteful and potentially regulated.</span><span class='qd'><b>Emptying the toner outdoors</b>: spreads contaminants.</span><span class='qd'><b>Rinsing them in a sink</b>: toner contaminates water and clogs drains.</span>" },
{ id:"D4-070", domain:4, obj:"4.4", diff:"medium", q:"What is the purpose of an ESD mat used together with a wrist strap?", options:["To cushion the technician's feet","To provide a grounded, static-dissipating work surface for components","To increase airflow","To store screws magnetically"], answer:1, explain:"<strong>To provide a grounded, static-dissipating work surface for components</strong> is correct because the mat safely channels static away from sensitive parts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To cushion the technician's feet</b>: it is a work surface, not a floor pad for comfort.</span><span class='qd'><b>To increase airflow</b>: unrelated.</span><span class='qd'><b>To store screws magnetically</b>: magnets near drives are discouraged.</span>" },
{ id:"D4-071", domain:4, obj:"4.4", diff:"hard", q:"A technician must service a power supply unit (PSU). Which safety practice is MOST important?", options:["Open the PSU and discharge it by touching the capacitors with bare hands","Do not open the sealed PSU; replace it as a unit because capacitors can store lethal charge","Leave the PSU plugged in while servicing","Wear an ESD strap connected directly to a wall outlet's hot wire"], answer:1, explain:"<strong>Do not open the sealed PSU; replace it as a unit because capacitors can store lethal charge</strong> is correct because PSU capacitors retain dangerous voltage even when unplugged, so techs replace rather than open them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Open the PSU and discharge it by touching the capacitors with bare hands</b>: extremely dangerous.</span><span class='qd'><b>Leave the PSU plugged in while servicing</b>: never service energized equipment.</span><span class='qd'><b>Wear an ESD strap connected directly to a wall outlet's hot wire</b>: lethal misuse of grounding.</span>" },
{ id:"D4-072", domain:4, obj:"4.4", diff:"easy", q:"Equipment grounding is important primarily to:", options:["Increase processing speed","Provide a safe path for fault current and reduce shock/ESD risk","Improve Wi-Fi signal","Reduce software bugs"], answer:1, explain:"<strong>Provide a safe path for fault current and reduce shock/ESD risk</strong> is correct because grounding protects people and equipment from electrical faults and static.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase processing speed</b>: grounding has no performance effect.</span><span class='qd'><b>Improve Wi-Fi signal</b>: unrelated.</span><span class='qd'><b>Reduce software bugs</b>: unrelated.</span>" },
{ id:"D4-073", domain:4, obj:"4.4", diff:"medium", q:"When should a technician NOT wear an ESD wrist strap?", options:["When handling RAM modules","When working on a powered, high-voltage device such as the inside of a CRT or PSU","When handling a motherboard","When installing an expansion card"], answer:1, explain:"<strong>When working on a powered, high-voltage device such as the inside of a CRT or PSU</strong> is correct because grounding yourself to a high-voltage source could route lethal current through you.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>When handling RAM modules</b>: a strap is recommended here.</span><span class='qd'><b>When handling a motherboard</b>: a strap protects the board.</span><span class='qd'><b>When installing an expansion card</b>: a strap is appropriate.</span>" },
{ id:"D4-074", domain:4, obj:"4.4", diff:"hard", q:"A technician finds a box of old NiCd and lithium batteries, broken CRTs, and empty toner cartridges. What is the BEST disposal approach?", options:["Bag everything and place it in the office dumpster","Sort and route each item to the appropriate recycling or hazardous waste program per local regulations","Burn the items in a safe outdoor area","Store them indefinitely in a supply closet"], answer:1, explain:"<strong>Sort and route each item to the appropriate recycling or hazardous waste program per local regulations</strong> is correct because each contains hazardous materials requiring proper, regulated disposal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bag everything and place it in the office dumpster</b>: illegal and harmful.</span><span class='qd'><b>Burn the items in a safe outdoor area</b>: dangerous and releases toxins.</span><span class='qd'><b>Store them indefinitely in a supply closet</b>: avoids proper disposal and poses hazards.</span>" },
{ id:"D4-075", domain:4, obj:"4.4", diff:"medium", q:"Proper power handling when servicing a desktop includes:", options:["Working on it while it is plugged in and powered on","Unplugging the system from AC power before opening the case","Touching the CPU pins to discharge static","Leaving the PSU switch on for grounding"], answer:1, explain:"<strong>Unplugging the system from AC power before opening the case</strong> is correct because removing power prevents shock and accidental damage during service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Working on it while it is plugged in and powered on</b>: unsafe.</span><span class='qd'><b>Touching the CPU pins to discharge static</b>: can damage the CPU.</span><span class='qd'><b>Leaving the PSU switch on for grounding</b>: improper and unsafe.</span>" },
{ id:"D4-076", domain:4, obj:"4.4", diff:"easy", q:"Which personal protective equipment best protects against inhaling fine particulate when blowing out dust?", options:["Safety glasses","Air filtration mask","ESD strap","Steel-toe boots"], answer:1, explain:"<strong>Air filtration mask</strong> is correct because it filters airborne dust and particulates from the breathing path.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Safety glasses</b>: protect eyes, not lungs.</span><span class='qd'><b>ESD strap</b>: prevents static, not inhalation.</span><span class='qd'><b>Steel-toe boots</b>: protect feet.</span>" },
{ id:"D4-077", domain:4, obj:"4.4", diff:"hard", q:"A heavy UPS must be moved to another rack. Two technicians are available. What is the BEST practice?", options:["One technician lifts it alone to save time","Use team lifting, keep backs straight, lift with legs, and clear the path first","Slide it across the floor by pushing with one foot","Lift it overhead to clear obstacles"], answer:1, explain:"<strong>Use team lifting, keep backs straight, lift with legs, and clear the path first</strong> is correct because heavy items should be team-lifted with proper technique and a clear route.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One technician lifts it alone to save time</b>: risks injury for heavy loads.</span><span class='qd'><b>Slide it across the floor by pushing with one foot</b>: unsafe and uncontrolled.</span><span class='qd'><b>Lift it overhead to clear obstacles</b>: dangerous and unnecessary.</span>" },
{ id:"D4-078", domain:4, obj:"4.4", diff:"medium", q:"What is the danger of using a magnetic-tipped screwdriver near a traditional hard disk drive?", options:["It can erase the BIOS","Strong magnetic fields could potentially affect data on magnetic media","It increases ESD risk","It speeds up corrosion"], answer:1, explain:"<strong>Strong magnetic fields could potentially affect data on magnetic media</strong> is correct because magnetic fields can interfere with data on spinning hard drives, so caution is advised.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It can erase the BIOS</b>: BIOS is flash memory, not magnetic.</span><span class='qd'><b>It increases ESD risk</b>: magnetism is not ESD.</span><span class='qd'><b>It speeds up corrosion</b>: unrelated.</span>" },
{ id:"D4-079", domain:4, obj:"4.4", diff:"easy", q:"What does ESD stand for, and what damage does it cause?", options:["Electrostatic Discharge; it can damage sensitive electronic components","Electrical Surge Detection; it prevents fires","Equipment Storage Drawer; it organizes parts","Enhanced System Diagnostics; it scans for malware"], answer:0, explain:"<strong>Electrostatic Discharge; it can damage sensitive electronic components</strong> is correct because ESD is the sudden flow of static electricity that can ruin chips and boards.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Electrical Surge Detection; it prevents fires</b>: not what ESD means.</span><span class='qd'><b>Equipment Storage Drawer; it organizes parts</b>: incorrect expansion.</span><span class='qd'><b>Enhanced System Diagnostics; it scans for malware</b>: incorrect expansion.</span>" },
{ id:"D4-080", domain:4, obj:"4.4", diff:"medium", q:"To minimize ESD damage while installing memory, which combination is BEST?", options:["High humidity reduced to near zero and carpeted floor","Wrist strap, ESD mat, and handling modules by the edges","Working in socks on carpet","Holding RAM by its gold contacts"], answer:1, explain:"<strong>Wrist strap, ESD mat, and handling modules by the edges</strong> is correct because grounding plus edge handling minimizes static damage to components.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>High humidity reduced to near zero and carpeted floor</b>: low humidity and carpet increase static.</span><span class='qd'><b>Working in socks on carpet</b>: generates static.</span><span class='qd'><b>Holding RAM by its gold contacts</b>: touching contacts risks ESD damage.</span>" },
{ id:"D4-081", domain:4, obj:"4.5", diff:"easy", q:"What document provides handling, storage, and safety information for chemicals like cleaning solvents?", options:["AUP","Safety Data Sheet (SDS/MSDS)","Incident report","Change request form"], answer:1, explain:"<strong>Safety Data Sheet (SDS/MSDS)</strong> is correct because an SDS details a chemical's hazards, handling, storage, and first-aid information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AUP</b>: governs acceptable IT use.</span><span class='qd'><b>Incident report</b>: documents an event.</span><span class='qd'><b>Change request form</b>: proposes a change.</span>" },
{ id:"D4-082", domain:4, obj:"4.5", diff:"easy", q:"A device that provides battery power during a blackout and allows safe shutdown is a:", options:["Surge suppressor","Uninterruptible power supply (UPS)","Power strip","KVM switch"], answer:1, explain:"<strong>Uninterruptible power supply (UPS)</strong> is correct because a UPS supplies battery backup power during outages so equipment can run or shut down safely.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Surge suppressor</b>: only protects against voltage spikes, no battery.</span><span class='qd'><b>Power strip</b>: just distributes outlets.</span><span class='qd'><b>KVM switch</b>: shares keyboard/video/mouse, not power.</span>" },
{ id:"D4-083", domain:4, obj:"4.5", diff:"easy", q:"A momentary loss of all electrical power is called a:", options:["Brownout","Surge","Blackout","Spike"], answer:2, explain:"<strong>Blackout</strong> is correct because a blackout is a total loss of power.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Brownout</b>: a drop in voltage, not total loss.</span><span class='qd'><b>Surge</b>: an over-voltage event.</span><span class='qd'><b>Spike</b>: a very brief over-voltage burst.</span>" },
{ id:"D4-084", domain:4, obj:"4.5", diff:"medium", q:"A prolonged drop in voltage that dims lights and can cause equipment instability is a:", options:["Blackout","Brownout","Surge","Spike"], answer:1, explain:"<strong>Brownout</strong> is correct because a brownout is a sustained reduction in voltage below normal levels.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Blackout</b>: a complete power loss.</span><span class='qd'><b>Surge</b>: an over-voltage condition.</span><span class='qd'><b>Spike</b>: a brief over-voltage burst.</span>" },
{ id:"D4-085", domain:4, obj:"4.5", diff:"medium", q:"Which device is designed to protect equipment from voltage spikes but does NOT provide power during an outage?", options:["UPS","Surge suppressor","Generator","Inverter"], answer:1, explain:"<strong>Surge suppressor</strong> is correct because it diverts excess voltage from spikes but has no battery to power devices during an outage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>UPS</b>: provides battery backup during outages.</span><span class='qd'><b>Generator</b>: supplies power during extended outages.</span><span class='qd'><b>Inverter</b>: converts DC to AC, not surge protection.</span>" },
{ id:"D4-086", domain:4, obj:"4.5", diff:"medium", q:"Why is maintaining proper temperature and humidity important in a server room?", options:["To save on lighting costs","To prevent overheating, condensation, and electrostatic discharge","To improve internet speed","To reduce software licensing"], answer:1, explain:"<strong>To prevent overheating, condensation, and electrostatic discharge</strong> is correct because high heat damages hardware, while too-low humidity raises ESD risk and too-high humidity causes condensation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To save on lighting costs</b>: unrelated.</span><span class='qd'><b>To improve internet speed</b>: unrelated.</span><span class='qd'><b>To reduce software licensing</b>: unrelated.</span>" },
{ id:"D4-087", domain:4, obj:"4.5", diff:"hard", q:"A server room's humidity is too low. What environmental risk does this create, and what is the fix?", options:["Risk of condensation; lower the humidity further","Increased ESD risk; raise humidity to a safe range using humidification","Increased fire risk; turn off all servers","Risk of corrosion; remove all UPS units"], answer:1, explain:"<strong>Increased ESD risk; raise humidity to a safe range using humidification</strong> is correct because dry air promotes static buildup, so increasing humidity to recommended levels reduces ESD.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk of condensation; lower the humidity further</b>: condensation comes from high humidity, and lowering it worsens ESD.</span><span class='qd'><b>Increased fire risk; turn off all servers</b>: low humidity is not primarily a fire risk.</span><span class='qd'><b>Risk of corrosion; remove all UPS units</b>: corrosion is a high-humidity risk and UPS removal is irrelevant.</span>" },
{ id:"D4-088", domain:4, obj:"4.5", diff:"hard", q:"An organization experiences frequent brief over-voltage spikes during storms damaging power supplies. Which solution BEST addresses this?", options:["A simple power strip","A surge suppressor (or UPS with surge protection)","A KVM switch","A longer extension cord"], answer:1, explain:"<strong>A surge suppressor (or UPS with surge protection)</strong> is correct because surge protection diverts spike energy away from equipment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A simple power strip</b>: most basic strips offer no real surge protection.</span><span class='qd'><b>A KVM switch</b>: shares peripherals, not power protection.</span><span class='qd'><b>A longer extension cord</b>: provides no protection.</span>" },
{ id:"D4-089", domain:4, obj:"4.5", diff:"medium", q:"Proper ventilation in equipment areas helps to:", options:["Increase static electricity","Dissipate heat and maintain safe operating temperatures","Block all airflow","Raise humidity to maximum"], answer:1, explain:"<strong>Dissipate heat and maintain safe operating temperatures</strong> is correct because ventilation removes heat to keep equipment within safe ranges.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase static electricity</b>: ventilation does not aim to raise static.</span><span class='qd'><b>Block all airflow</b>: the opposite of ventilation.</span><span class='qd'><b>Raise humidity to maximum</b>: not the goal.</span>" },
{ id:"D4-090", domain:4, obj:"4.5", diff:"hard", q:"Where should an SDS for cleaning chemicals be kept, and why?", options:["Locked away so no one can read it","Readily accessible to workers who may handle or be exposed to the chemical","Only at the manufacturer's office","Deleted after purchase to save space"], answer:1, explain:"<strong>Readily accessible to workers who may handle or be exposed to the chemical</strong> is correct because SDS information must be available so workers know hazards and first-aid steps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Locked away so no one can read it</b>: defeats its safety purpose.</span><span class='qd'><b>Only at the manufacturer's office</b>: must be on-site where the chemical is used.</span><span class='qd'><b>Deleted after purchase to save space</b>: it must be retained.</span>" },
{ id:"D4-091", domain:4, obj:"4.5", diff:"easy", q:"A very brief, intense increase in voltage is called a:", options:["Brownout","Blackout","Spike","Sag"], answer:2, explain:"<strong>Spike</strong> is correct because a spike is a sudden, very short-duration over-voltage event.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Brownout</b>: a sustained voltage drop.</span><span class='qd'><b>Blackout</b>: total power loss.</span><span class='qd'><b>Sag</b>: a brief voltage drop, not an increase.</span>" },
{ id:"D4-092", domain:4, obj:"4.5", diff:"medium", q:"During a multi-hour power outage at a small office, which solution keeps critical servers running the LONGEST?", options:["A surge suppressor","A standalone power strip","A backup generator","An ESD mat"], answer:2, explain:"<strong>A backup generator</strong> is correct because generators can supply power for extended outages, far longer than a UPS battery alone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A surge suppressor</b>: provides no power during outages.</span><span class='qd'><b>A standalone power strip</b>: only distributes outlets.</span><span class='qd'><b>An ESD mat</b>: a static-control surface, not a power source.</span>" },
{ id:"D4-093", domain:4, obj:"4.5", diff:"medium", q:"A technician spills a cleaning solvent and is unsure of the first-aid response. What is the BEST immediate reference?", options:["The AUP","The Safety Data Sheet (SDS) for that solvent","The network topology diagram","The change request form"], answer:1, explain:"<strong>The Safety Data Sheet (SDS) for that solvent</strong> is correct because the SDS lists first-aid measures, hazards, and cleanup guidance for that chemical.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AUP</b>: governs IT usage.</span><span class='qd'><b>The network topology diagram</b>: shows connectivity.</span><span class='qd'><b>The change request form</b>: proposes changes.</span>" },
{ id:"D4-094", domain:4, obj:"4.5", diff:"hard", q:"A UPS is rated for 10 minutes of runtime, but the building's outages often last over an hour. What is the BEST role for the UPS in this scenario?", options:["Replace it with a surge suppressor","Use it to bridge power for a safe, graceful shutdown or until a generator takes over","Expect it to run servers for the full hour","Rely on it as the only power protection needed"], answer:1, explain:"<strong>Use it to bridge power for a safe, graceful shutdown or until a generator takes over</strong> is correct because a UPS is designed for short-term continuity and orderly shutdown, not long outages.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace it with a surge suppressor</b>: that removes battery backup entirely.</span><span class='qd'><b>Expect it to run servers for the full hour</b>: exceeds its rated runtime.</span><span class='qd'><b>Rely on it as the only power protection needed</b>: long outages need generator backup.</span>" },
{ id:"D4-095", domain:4, obj:"4.5", diff:"easy", q:"Which of the following BEST describes the function of a battery backup UPS?", options:["It only filters internet traffic","It supplies temporary power and conditions voltage during disturbances","It increases CPU clock speed","It stores backup files"], answer:1, explain:"<strong>It supplies temporary power and conditions voltage during disturbances</strong> is correct because a UPS provides battery power and often line conditioning during outages and fluctuations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It only filters internet traffic</b>: that is a firewall function.</span><span class='qd'><b>It increases CPU clock speed</b>: unrelated.</span><span class='qd'><b>It stores backup files</b>: that is a backup system.</span>" },
{ id:"D4-096", domain:4, obj:"4.5", diff:"medium", q:"High humidity in a data center is dangerous primarily because it can cause:", options:["Excessive static discharge","Condensation and corrosion on electronics","Faster fan speeds","Brighter displays"], answer:1, explain:"<strong>Condensation and corrosion on electronics</strong> is correct because excess moisture leads to condensation and corrosion damage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Excessive static discharge</b>: that is a low-humidity risk.</span><span class='qd'><b>Faster fan speeds</b>: not a humidity effect.</span><span class='qd'><b>Brighter displays</b>: unrelated.</span>" },
{ id:"D4-097", domain:4, obj:"4.5", diff:"hard", q:"An office wants both spike protection and ride-through power for short outages on its point-of-sale system. Which single device best meets both needs?", options:["A basic power strip","A UPS with integrated surge protection","A surge suppressor only","An ESD wrist strap"], answer:1, explain:"<strong>A UPS with integrated surge protection</strong> is correct because it provides battery ride-through power and surge protection in one unit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A basic power strip</b>: offers neither real surge protection nor battery.</span><span class='qd'><b>A surge suppressor only</b>: lacks battery backup.</span><span class='qd'><b>An ESD wrist strap</b>: unrelated to power protection.</span>" },
{ id:"D4-098", domain:4, obj:"4.5", diff:"medium", q:"MSDS/SDS sheets are MOST closely associated with which environmental concern?", options:["Network bandwidth","Safe handling and disposal of chemicals and hazardous materials","Backup rotation schedules","Software licensing"], answer:1, explain:"<strong>Safe handling and disposal of chemicals and hazardous materials</strong> is correct because SDS documents describe chemical hazards, handling, and disposal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Network bandwidth</b>: unrelated.</span><span class='qd'><b>Backup rotation schedules</b>: a backup topic.</span><span class='qd'><b>Software licensing</b>: a different domain area.</span>" },
{ id:"D4-099", domain:4, obj:"4.5", diff:"easy", q:"Which event is characterized by a sudden increase in voltage lasting longer than a momentary spike?", options:["Sag","Surge","Blackout","Brownout"], answer:1, explain:"<strong>Surge</strong> is correct because a surge is an over-voltage condition lasting longer than a brief spike.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sag</b>: a brief drop in voltage.</span><span class='qd'><b>Blackout</b>: total power loss.</span><span class='qd'><b>Brownout</b>: a sustained voltage reduction.</span>" },
{ id:"D4-100", domain:4, obj:"4.5", diff:"hard", q:"A technician notices a server room consistently running near the upper temperature limit. Beyond adding cooling, which proactive control reduces risk of overheating-related failures?", options:["Reducing humidity to near zero","Improving ventilation and airflow management (e.g., hot/cold aisle, unblocked vents)","Removing all UPS units","Disabling surge suppressors"], answer:1, explain:"<strong>Improving ventilation and airflow management (e.g., hot/cold aisle, unblocked vents)</strong> is correct because effective airflow management removes heat and lowers operating temperatures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reducing humidity to near zero</b>: raises ESD risk and does not fix heat.</span><span class='qd'><b>Removing all UPS units</b>: reduces power protection without helping cooling.</span><span class='qd'><b>Disabling surge suppressors</b>: removes protection and does not address heat.</span>" },
{ id:"D4-101", domain:4, obj:"4.6", diff:"easy", q:"In incident response, the documented record of who handled evidence and when is called the:", options:["Chain of custody","Acceptable use policy","Backup log","Splash screen"], answer:0, explain:"<strong>Chain of custody</strong> is correct because it tracks every person who handled evidence and when, preserving its integrity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Acceptable use policy</b>: governs IT usage.</span><span class='qd'><b>Backup log</b>: records backup activity.</span><span class='qd'><b>Splash screen</b>: a startup notice.</span>" },
{ id:"D4-102", domain:4, obj:"4.6", diff:"easy", q:"Which type of data is PII?", options:["A public marketing brochure","Information that can identify an individual, such as a Social Security number","A company logo","An open-source license file"], answer:1, explain:"<strong>Information that can identify an individual, such as a Social Security number</strong> is correct because PII is personally identifiable information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A public marketing brochure</b>: public, non-identifying.</span><span class='qd'><b>A company logo</b>: not personal data.</span><span class='qd'><b>An open-source license file</b>: a licensing document.</span>" },
{ id:"D4-103", domain:4, obj:"4.6", diff:"medium", q:"PCI DSS is a standard primarily concerned with protecting:", options:["Patient health records","Payment card (credit/debit) data","European citizens' privacy rights","Open-source code"], answer:1, explain:"<strong>Payment card (credit/debit) data</strong> is correct because PCI DSS governs the secure handling of cardholder data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Patient health records</b>: that is HIPAA/PHI.</span><span class='qd'><b>European citizens' privacy rights</b>: that is GDPR.</span><span class='qd'><b>Open-source code</b>: a licensing topic.</span>" },
{ id:"D4-104", domain:4, obj:"4.6", diff:"medium", q:"GDPR is a regulation that primarily governs:", options:["Payment card security","The privacy and protection of personal data of individuals in the EU","Open-source software distribution","Server room temperature"], answer:1, explain:"<strong>The privacy and protection of personal data of individuals in the EU</strong> is correct because GDPR is the EU's data protection regulation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Payment card security</b>: that is PCI DSS.</span><span class='qd'><b>Open-source software distribution</b>: a licensing topic.</span><span class='qd'><b>Server room temperature</b>: an environmental topic.</span>" },
{ id:"D4-105", domain:4, obj:"4.6", diff:"medium", q:"PHI (protected health information) is regulated under which framework?", options:["PCI DSS","HIPAA","GDPR only","EULA"], answer:1, explain:"<strong>HIPAA</strong> is correct because HIPAA governs the protection of health information in the United States.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PCI DSS</b>: covers payment card data.</span><span class='qd'><b>GDPR only</b>: GDPR is broad EU privacy law, not the specific PHI framework referenced here.</span><span class='qd'><b>EULA</b>: a software license agreement.</span>" },
{ id:"D4-106", domain:4, obj:"4.6", diff:"hard", q:"A technician discovers illegal content on a user's company laptop. As the first responder, what is the BEST action?", options:["Delete the content immediately","Preserve the data, document findings, and report through proper channels without altering evidence","Email the files to your manager","Continue using the laptop normally"], answer:1, explain:"<strong>Preserve the data, document findings, and report through proper channels without altering evidence</strong> is correct because a first responder must protect evidence integrity and escalate appropriately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete the content immediately</b>: destroys evidence.</span><span class='qd'><b>Email the files to your manager</b>: improperly handles and copies evidence.</span><span class='qd'><b>Continue using the laptop normally</b>: alters and contaminates evidence.</span>" },
{ id:"D4-107", domain:4, obj:"4.6", diff:"hard", q:"Why is data preservation important during an incident investigation?", options:["It speeds up the computer","It maintains evidence in an unaltered state so it remains valid and admissible","It frees disk space","It updates the operating system"], answer:1, explain:"<strong>It maintains evidence in an unaltered state so it remains valid and admissible</strong> is correct because preserving original data keeps evidence credible for investigation or legal action.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It speeds up the computer</b>: unrelated.</span><span class='qd'><b>It frees disk space</b>: deletion would harm evidence.</span><span class='qd'><b>It updates the operating system</b>: unrelated and would alter the system.</span>" },
{ id:"D4-108", domain:4, obj:"4.6", diff:"medium", q:"Which licensing model allows a single organization to deploy software across many systems under one agreement?", options:["Personal license","Enterprise license","Open-source GPL","Trial license"], answer:1, explain:"<strong>Enterprise license</strong> is correct because enterprise licensing covers broad organizational deployment under one agreement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Personal license</b>: typically for a single individual/device.</span><span class='qd'><b>Open-source GPL</b>: a free software license, not an enterprise volume agreement.</span><span class='qd'><b>Trial license</b>: temporary, limited use.</span>" },
{ id:"D4-109", domain:4, obj:"4.6", diff:"medium", q:"What is the key difference between open-source and commercial (closed-source) software licensing?", options:["Open-source is always malware-free","Open-source typically allows viewing/modifying the source code, while commercial software restricts it","Commercial software is always free","Open-source software cannot be used in business"], answer:1, explain:"<strong>Open-source typically allows viewing/modifying the source code, while commercial software restricts it</strong> is correct because that source-code access is the defining difference.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Open-source is always malware-free</b>: licensing does not guarantee safety.</span><span class='qd'><b>Commercial software is always free</b>: commercial usually requires payment.</span><span class='qd'><b>Open-source software cannot be used in business</b>: it commonly is.</span>" },
{ id:"D4-110", domain:4, obj:"4.6", diff:"medium", q:"DRM (Digital Rights Management) is primarily used to:", options:["Encrypt server room temperatures","Control how licensed digital content can be used, copied, or distributed","Speed up backups","Provide off-site storage"], answer:1, explain:"<strong>Control how licensed digital content can be used, copied, or distributed</strong> is correct because DRM enforces usage restrictions on protected content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt server room temperatures</b>: nonsensical.</span><span class='qd'><b>Speed up backups</b>: unrelated.</span><span class='qd'><b>Provide off-site storage</b>: unrelated.</span>" },
{ id:"D4-111", domain:4, obj:"4.6", diff:"easy", q:"What is a EULA?", options:["A backup rotation scheme","An end-user license agreement that defines the terms for using software","A network diagram","A power protection device"], answer:1, explain:"<strong>An end-user license agreement that defines the terms for using software</strong> is correct because a EULA is the legal contract between the software vendor and the user.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A backup rotation scheme</b>: that is GFS.</span><span class='qd'><b>A network diagram</b>: shows connectivity.</span><span class='qd'><b>A power protection device</b>: that is a UPS/surge suppressor.</span>" },
{ id:"D4-112", domain:4, obj:"4.6", diff:"hard", q:"During an incident, multiple people handle a seized drive. To keep evidence valid, what MUST be recorded in the chain of custody?", options:["Only the final examiner's name","Each transfer: who had it, when, where, and the purpose, with signatures","Just the date it was seized","Only the file names on the drive"], answer:1, explain:"<strong>Each transfer: who had it, when, where, and the purpose, with signatures</strong> is correct because a complete custody log documents every handoff to prove the evidence was not tampered with.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the final examiner's name</b>: omits prior handlers.</span><span class='qd'><b>Just the date it was seized</b>: incomplete.</span><span class='qd'><b>Only the file names on the drive</b>: not a custody record.</span>" },
{ id:"D4-113", domain:4, obj:"4.6", diff:"easy", q:"Which of the following is an example of regulated data requiring special handling?", options:["A public press release","A customer's credit card number (PCI data)","A company holiday calendar","An open-source readme file"], answer:1, explain:"<strong>A customer's credit card number (PCI data)</strong> is correct because payment card data is regulated under PCI DSS and requires protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A public press release</b>: intended for public release.</span><span class='qd'><b>A company holiday calendar</b>: not sensitive.</span><span class='qd'><b>An open-source readme file</b>: public documentation.</span>" },
{ id:"D4-114", domain:4, obj:"4.6", diff:"hard", q:"A technician images a suspect drive for analysis. Why analyze the copy rather than the original?", options:["Copies are faster to read","Working on a forensic copy preserves the original evidence intact","Originals cannot be opened","Copies use less storage"], answer:1, explain:"<strong>Working on a forensic copy preserves the original evidence intact</strong> is correct because analyzing a copy avoids altering the original, maintaining its integrity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Copies are faster to read</b>: not the reason.</span><span class='qd'><b>Originals cannot be opened</b>: they can, but should not be altered.</span><span class='qd'><b>Copies use less storage</b>: forensic images are typically the same size.</span>" },
{ id:"D4-115", domain:4, obj:"4.6", diff:"medium", q:"A user installs a copy of commercial software licensed for one personal device onto twenty office workstations. What violation is this?", options:["GDPR violation","Software license (EULA) violation / piracy","Chain of custody violation","PCI violation"], answer:1, explain:"<strong>Software license (EULA) violation / piracy</strong> is correct because deploying a single-device license to many systems breaches the license terms.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GDPR violation</b>: GDPR concerns personal data privacy.</span><span class='qd'><b>Chain of custody violation</b>: relates to evidence handling.</span><span class='qd'><b>PCI violation</b>: relates to card data.</span>" },
{ id:"D4-116", domain:4, obj:"4.6", diff:"medium", q:"What is the role of the first responder in a security incident?", options:["To repair all damage immediately","To identify, contain, and preserve evidence while following procedures and escalating","To delete suspicious files","To ignore the incident until management responds"], answer:1, explain:"<strong>To identify, contain, and preserve evidence while following procedures and escalating</strong> is correct because the first responder secures the scene and protects evidence per policy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To repair all damage immediately</b>: repairs can destroy evidence.</span><span class='qd'><b>To delete suspicious files</b>: destroys evidence.</span><span class='qd'><b>To ignore the incident until management responds</b>: fails the response duty.</span>" },
{ id:"D4-117", domain:4, obj:"4.6", diff:"hard", q:"A company stores EU customers' personal data and US patients' health records. Which two regulations apply, respectively?", options:["PCI DSS and EULA","GDPR and HIPAA","DRM and AUP","SOP and GFS"], answer:1, explain:"<strong>GDPR and HIPAA</strong> is correct because GDPR covers EU personal data and HIPAA covers US protected health information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PCI DSS and EULA</b>: PCI is card data; EULA is licensing.</span><span class='qd'><b>DRM and AUP</b>: content control and usage policy.</span><span class='qd'><b>SOP and GFS</b>: a procedure and a backup scheme.</span>" },
{ id:"D4-118", domain:4, obj:"4.6", diff:"medium", q:"Why must incident response include thorough documentation of all actions taken?", options:["To increase the file size of reports","To create an accurate, defensible record for analysis, legal use, and lessons learned","To slow down the response","To replace the chain of custody"], answer:1, explain:"<strong>To create an accurate, defensible record for analysis, legal use, and lessons learned</strong> is correct because documentation supports investigation, accountability, and improvement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To increase the file size of reports</b>: not a goal.</span><span class='qd'><b>To slow down the response</b>: documentation supports, not hinders.</span><span class='qd'><b>To replace the chain of custody</b>: documentation complements, not replaces, custody records.</span>" },
{ id:"D4-119", domain:4, obj:"4.6", diff:"easy", q:"Which is the BEST description of a personal (single-user) software license?", options:["Allows unlimited business deployment","Permits use by one user, typically on a limited number of personal devices","Grants source-code modification rights to anyone","Covers an entire enterprise's installations"], answer:1, explain:"<strong>Permits use by one user, typically on a limited number of personal devices</strong> is correct because personal licenses are scoped to an individual's limited use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allows unlimited business deployment</b>: that is enterprise licensing.</span><span class='qd'><b>Grants source-code modification rights to anyone</b>: that is open-source.</span><span class='qd'><b>Covers an entire enterprise's installations</b>: that is enterprise licensing.</span>" },
{ id:"D4-120", domain:4, obj:"4.6", diff:"hard", q:"While preserving evidence on a running machine, which consideration is MOST important regarding volatile data?", options:["Reboot first to clear memory","Capture volatile data (e.g., RAM contents) before powering down, since it is lost on shutdown","Always power off immediately","Volatile data is never relevant"], answer:1, explain:"<strong>Capture volatile data (e.g., RAM contents) before powering down, since it is lost on shutdown</strong> is correct because volatile memory is lost when power is removed and may hold key evidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reboot first to clear memory</b>: destroys volatile evidence.</span><span class='qd'><b>Always power off immediately</b>: loses volatile data.</span><span class='qd'><b>Volatile data is never relevant</b>: it can be highly relevant.</span>" },
{ id:"D4-121", domain:4, obj:"4.7", diff:"easy", q:"When communicating with customers, a technician should:", options:["Use heavy technical jargon to sound expert","Use clear language the customer can understand, avoiding unnecessary jargon","Speak only in acronyms","Interrupt frequently to save time"], answer:1, explain:"<strong>Use clear language the customer can understand, avoiding unnecessary jargon</strong> is correct because plain language improves understanding and customer experience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use heavy technical jargon to sound expert</b>: confuses customers.</span><span class='qd'><b>Speak only in acronyms</b>: hinders communication.</span><span class='qd'><b>Interrupt frequently to save time</b>: rude and counterproductive.</span>" },
{ id:"D4-122", domain:4, obj:"4.7", diff:"easy", q:"Active listening during a support call means:", options:["Talking over the customer","Fully focusing on the customer, confirming understanding, and not interrupting","Putting the customer on hold immediately","Reading email while they talk"], answer:1, explain:"<strong>Fully focusing on the customer, confirming understanding, and not interrupting</strong> is correct because active listening ensures the technician truly understands the issue.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Talking over the customer</b>: the opposite of listening.</span><span class='qd'><b>Putting the customer on hold immediately</b>: dismissive.</span><span class='qd'><b>Reading email while they talk</b>: a distraction that hurts listening.</span>" },
{ id:"D4-123", domain:4, obj:"4.7", diff:"medium", q:"A customer becomes angry and raises their voice. What is the BEST professional response?", options:["Raise your voice to match theirs","Stay calm, listen, empathize, and focus on resolving the issue","Hang up immediately","Tell them they are wrong"], answer:1, explain:"<strong>Stay calm, listen, empathize, and focus on resolving the issue</strong> is correct because remaining calm and empathetic de-escalates difficult situations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Raise your voice to match theirs</b>: escalates conflict.</span><span class='qd'><b>Hang up immediately</b>: unprofessional and unhelpful.</span><span class='qd'><b>Tell them they are wrong</b>: provokes the customer.</span>" },
{ id:"D4-124", domain:4, obj:"4.7", diff:"medium", q:"Why is punctuality important for an on-site technician?", options:["It guarantees a faster computer","It shows respect for the customer's time and builds trust","It reduces the need for tools","It eliminates the need to document work"], answer:1, explain:"<strong>It shows respect for the customer's time and builds trust</strong> is correct because being on time demonstrates professionalism and reliability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees a faster computer</b>: unrelated to performance.</span><span class='qd'><b>It reduces the need for tools</b>: irrelevant.</span><span class='qd'><b>It eliminates the need to document work</b>: documentation is still required.</span>" },
{ id:"D4-125", domain:4, obj:"4.7", diff:"medium", q:"While working at a customer's desk, your personal phone rings repeatedly. What is the BEST practice?", options:["Answer it and chat while you work","Silence the phone and avoid the distraction while serving the customer","Ask the customer to answer it","Stop work to check social media"], answer:1, explain:"<strong>Silence the phone and avoid the distraction while serving the customer</strong> is correct because avoiding distractions keeps focus on the customer and the task.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Answer it and chat while you work</b>: unprofessional and distracting.</span><span class='qd'><b>Ask the customer to answer it</b>: inappropriate.</span><span class='qd'><b>Stop work to check social media</b>: a personal distraction during work.</span>" },
{ id:"D4-126", domain:4, obj:"4.7", diff:"hard", q:"A repair will take longer than initially estimated. What is the MOST professional approach?", options:["Say nothing and hope the customer does not notice","Proactively set realistic expectations by communicating the delay and revised timeline","Blame the manufacturer loudly","Rush and skip steps to meet the original time"], answer:1, explain:"<strong>Proactively set realistic expectations by communicating the delay and revised timeline</strong> is correct because setting and updating expectations builds trust and reduces frustration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Say nothing and hope the customer does not notice</b>: erodes trust.</span><span class='qd'><b>Blame the manufacturer loudly</b>: unprofessional.</span><span class='qd'><b>Rush and skip steps to meet the original time</b>: risks quality and reliability.</span>" },
{ id:"D4-127", domain:4, obj:"4.7", diff:"medium", q:"While repairing a manager's laptop, you notice confidential salary files. What should you do?", options:["Read them out of curiosity","Leave the files untouched and keep their existence confidential","Copy them for later reference","Share them with coworkers"], answer:1, explain:"<strong>Leave the files untouched and keep their existence confidential</strong> is correct because confidential materials must not be accessed or disclosed beyond the task at hand.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Read them out of curiosity</b>: violates privacy.</span><span class='qd'><b>Copy them for later reference</b>: unauthorized data handling.</span><span class='qd'><b>Share them with coworkers</b>: a serious confidentiality breach.</span>" },
{ id:"D4-128", domain:4, obj:"4.7", diff:"medium", q:"Cultural sensitivity in customer interactions means:", options:["Treating everyone identically regardless of context","Being respectful and aware of differences in customs, language, and communication styles","Avoiding all customers from other regions","Using slang to seem friendly"], answer:1, explain:"<strong>Being respectful and aware of differences in customs, language, and communication styles</strong> is correct because cultural sensitivity fosters respectful, effective communication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Treating everyone identically regardless of context</b>: ignores meaningful differences.</span><span class='qd'><b>Avoiding all customers from other regions</b>: discriminatory and unprofessional.</span><span class='qd'><b>Using slang to seem friendly</b>: can be confusing or inappropriate.</span>" },
{ id:"D4-129", domain:4, obj:"4.7", diff:"hard", q:"A customer keeps describing unrelated symptoms and you are unsure of the actual problem. Which technique BEST clarifies the issue?", options:["Assume you know and start replacing parts","Use active listening and ask clarifying, open-ended questions to confirm the real problem","Tell the customer to stop talking","End the call and escalate immediately"], answer:1, explain:"<strong>Use active listening and ask clarifying, open-ended questions to confirm the real problem</strong> is correct because clarifying questions and listening reveal the true issue.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume you know and start replacing parts</b>: risks fixing the wrong thing.</span><span class='qd'><b>Tell the customer to stop talking</b>: rude and counterproductive.</span><span class='qd'><b>End the call and escalate immediately</b>: premature without understanding.</span>" },
{ id:"D4-130", domain:4, obj:"4.7", diff:"easy", q:"Maintaining a positive attitude and projecting confidence with customers helps to:", options:["Slow down the repair","Reassure the customer and improve their overall experience","Avoid documenting the work","Increase electrical hazards"], answer:1, explain:"<strong>Reassure the customer and improve their overall experience</strong> is correct because a positive, confident demeanor builds customer trust and satisfaction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slow down the repair</b>: attitude does not slow work.</span><span class='qd'><b>Avoid documenting the work</b>: documentation is still required.</span><span class='qd'><b>Increase electrical hazards</b>: unrelated.</span>" },
{ id:"D4-131", domain:4, obj:"4.7", diff:"hard", q:"A difficult customer demands a solution you cannot promise. What is the MOST professional response?", options:["Promise whatever they want to calm them down","Avoid arguing, acknowledge their concern, and offer realistic options and next steps","Tell them their request is impossible and end the conversation","Refer them to a competitor"], answer:1, explain:"<strong>Avoid arguing, acknowledge their concern, and offer realistic options and next steps</strong> is correct because acknowledging concerns while setting honest expectations manages difficult customers professionally.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Promise whatever they want to calm them down</b>: creates false expectations.</span><span class='qd'><b>Tell them their request is impossible and end the conversation</b>: dismissive.</span><span class='qd'><b>Refer them to a competitor</b>: abandons the customer.</span>" },
{ id:"D4-132", domain:4, obj:"4.7", diff:"medium", q:"Which behavior demonstrates professionalism when arriving at a client site?", options:["Arriving late without notice","Being on time, dressed appropriately, and greeting the client courteously","Walking in without acknowledging anyone","Taking personal calls in front of the client"], answer:1, explain:"<strong>Being on time, dressed appropriately, and greeting the client courteously</strong> is correct because punctuality, appropriate appearance, and courtesy reflect professionalism.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Arriving late without notice</b>: disrespects the client's time.</span><span class='qd'><b>Walking in without acknowledging anyone</b>: rude.</span><span class='qd'><b>Taking personal calls in front of the client</b>: a distraction.</span>" },
{ id:"D4-133", domain:4, obj:"4.7", diff:"medium", q:"A user explains their problem using incorrect technical terms. The BEST professional approach is to:", options:["Correct them harshly to assert authority","Listen patiently, gently clarify terms if needed, and avoid being condescending","Mock the mistake to lighten the mood","Ignore what they say entirely"], answer:1, explain:"<strong>Listen patiently, gently clarify terms if needed, and avoid being condescending</strong> is correct because respectful clarification maintains rapport and gathers accurate information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Correct them harshly to assert authority</b>: damages rapport.</span><span class='qd'><b>Mock the mistake to lighten the mood</b>: unprofessional.</span><span class='qd'><b>Ignore what they say entirely</b>: loses useful detail.</span>" },
{ id:"D4-134", domain:4, obj:"4.7", diff:"easy", q:"Setting expectations with a customer typically includes:", options:["Promising instant fixes for every issue","Communicating realistic timelines, possible outcomes, and follow-up steps","Avoiding all communication until done","Telling them nothing can be fixed"], answer:1, explain:"<strong>Communicating realistic timelines, possible outcomes, and follow-up steps</strong> is correct because clear expectations help customers understand the process and reduce frustration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Promising instant fixes for every issue</b>: unrealistic.</span><span class='qd'><b>Avoiding all communication until done</b>: leaves customers uninformed.</span><span class='qd'><b>Telling them nothing can be fixed</b>: discouraging and often untrue.</span>" },
{ id:"D4-135", domain:4, obj:"4.7", diff:"hard", q:"A customer interrupts your explanation repeatedly. To maintain professionalism and still help them, you should:", options:["Stop talking and let them figure it out alone","Remain patient, let them finish, then calmly continue and confirm mutual understanding","Speak louder to drown them out","Tell them they are not letting you work"], answer:1, explain:"<strong>Remain patient, let them finish, then calmly continue and confirm mutual understanding</strong> is correct because patience and confirming understanding keep the interaction productive.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stop talking and let them figure it out alone</b>: abandons the customer.</span><span class='qd'><b>Speak louder to drown them out</b>: escalates tension.</span><span class='qd'><b>Tell them they are not letting you work</b>: confrontational.</span>" },
{ id:"D4-136", domain:4, obj:"4.8", diff:"easy", q:"Which file extension indicates a Windows PowerShell script?", options:[".bat",".ps1",".sh",".vbs"], answer:1, explain:"<strong>.ps1</strong> is correct because .ps1 is the PowerShell script extension.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>.bat</b>: a Windows batch file.</span><span class='qd'><b>.sh</b>: a shell script for Unix/Linux.</span><span class='qd'><b>.vbs</b>: a VBScript file.</span>" },
{ id:"D4-137", domain:4, obj:"4.8", diff:"easy", q:"Which file extension is used for a Linux/Unix shell script?", options:[".ps1",".bat",".sh",".js"], answer:2, explain:"<strong>.sh</strong> is correct because .sh denotes a shell script in Unix/Linux environments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>.ps1</b>: PowerShell on Windows.</span><span class='qd'><b>.bat</b>: a Windows batch file.</span><span class='qd'><b>.js</b>: a JavaScript file.</span>" },
{ id:"D4-138", domain:4, obj:"4.8", diff:"easy", q:"Which file extension identifies a Python script?", options:[".py",".vbs",".bat",".sh"], answer:0, explain:"<strong>.py</strong> is correct because .py is the standard Python script extension.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>.vbs</b>: a VBScript file.</span><span class='qd'><b>.bat</b>: a Windows batch file.</span><span class='qd'><b>.sh</b>: a shell script.</span>" },
{ id:"D4-139", domain:4, obj:"4.8", diff:"medium", q:"A .bat file is BEST described as:", options:["A Python program","A Windows batch script of command-line instructions","A Linux shell script","A compiled executable"], answer:1, explain:"<strong>A Windows batch script of command-line instructions</strong> is correct because .bat files run a sequence of CMD commands on Windows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A Python program</b>: that uses .py.</span><span class='qd'><b>A Linux shell script</b>: that uses .sh.</span><span class='qd'><b>A compiled executable</b>: batch files are scripts, not compiled.</span>" },
{ id:"D4-140", domain:4, obj:"4.8", diff:"medium", q:"In scripting, what is the purpose of a variable?", options:["To permanently disable the script","To store a value that can be referenced and changed during execution","To add comments","To compile the script"], answer:1, explain:"<strong>To store a value that can be referenced and changed during execution</strong> is correct because variables hold data the script can read and modify.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To permanently disable the script</b>: not a variable's role.</span><span class='qd'><b>To add comments</b>: comments are non-executing notes.</span><span class='qd'><b>To compile the script</b>: scripts are interpreted, not compiled by variables.</span>" },
{ id:"D4-141", domain:4, obj:"4.8", diff:"medium", q:"What is the purpose of a loop in a script?", options:["To stop the script after one line","To repeat a block of instructions multiple times","To encrypt the script","To rename the file"], answer:1, explain:"<strong>To repeat a block of instructions multiple times</strong> is correct because loops execute code repeatedly until a condition is met.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To stop the script after one line</b>: that is the opposite of looping.</span><span class='qd'><b>To encrypt the script</b>: unrelated.</span><span class='qd'><b>To rename the file</b>: unrelated.</span>" },
{ id:"D4-142", domain:4, obj:"4.8", diff:"easy", q:"Why do programmers include comments in scripts?", options:["To make the script run faster","To explain what the code does for human readers, ignored during execution","To define variables","To create loops"], answer:1, explain:"<strong>To explain what the code does for human readers, ignored during execution</strong> is correct because comments document intent and are not executed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make the script run faster</b>: comments do not affect speed.</span><span class='qd'><b>To define variables</b>: that is a separate construct.</span><span class='qd'><b>To create loops</b>: comments do not create loops.</span>" },
{ id:"D4-143", domain:4, obj:"4.8", diff:"medium", q:"Which is a common, appropriate use case for scripting in IT?", options:["Replacing all hardware","Automating tasks like remapping drives, installing applications, or restarting machines","Painting the server room","Negotiating software licenses"], answer:1, explain:"<strong>Automating tasks like remapping drives, installing applications, or restarting machines</strong> is correct because scripts automate repetitive administrative tasks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replacing all hardware</b>: a physical, not scripting, task.</span><span class='qd'><b>Painting the server room</b>: unrelated.</span><span class='qd'><b>Negotiating software licenses</b>: a business activity.</span>" },
{ id:"D4-144", domain:4, obj:"4.8", diff:"hard", q:"A technician downloads an unknown .ps1 script from the internet to fix an issue. What is the MOST important consideration before running it?", options:["Its file size","The risk it may unintentionally introduce malware or change settings, so review and verify the source first","The color of the icon","Whether it has comments"], answer:1, explain:"<strong>The risk it may unintentionally introduce malware or change settings, so review and verify the source first</strong> is correct because untrusted scripts can carry malware or make harmful changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Its file size</b>: size does not indicate safety.</span><span class='qd'><b>The color of the icon</b>: irrelevant.</span><span class='qd'><b>Whether it has comments</b>: comments do not guarantee safety.</span>" },
{ id:"D4-145", domain:4, obj:"4.8", diff:"medium", q:"A .vbs file is associated with which scripting technology?", options:["Python","VBScript on Windows","Bash on Linux","JavaScript in browsers only"], answer:1, explain:"<strong>VBScript on Windows</strong> is correct because .vbs files are VBScript scripts that run via the Windows Script Host.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Python</b>: uses .py.</span><span class='qd'><b>Bash on Linux</b>: uses .sh.</span><span class='qd'><b>JavaScript in browsers only</b>: JS uses .js and runs in more than browsers.</span>" },
{ id:"D4-146", domain:4, obj:"4.8", diff:"hard", q:"An automated script is scheduled to run nightly backups but has a bug that deletes files instead. Which scripting risk does this illustrate?", options:["Improved performance","Inadvertently changing settings or causing data loss due to script errors","Reduced electricity use","Better cultural sensitivity"], answer:1, explain:"<strong>Inadvertently changing settings or causing data loss due to script errors</strong> is correct because poorly written or untested scripts can unintentionally cause harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Improved performance</b>: not the risk shown.</span><span class='qd'><b>Reduced electricity use</b>: irrelevant.</span><span class='qd'><b>Better cultural sensitivity</b>: unrelated to scripting risk.</span>" },
{ id:"D4-147", domain:4, obj:"4.8", diff:"easy", q:"Which scripting use case would gather system information from many machines automatically?", options:["A script that queries and reports hardware/OS details","Manually writing down each spec by hand","Painting asset tags","Replacing all RAM"], answer:0, explain:"<strong>A script that queries and reports hardware/OS details</strong> is correct because scripting can automate information gathering across systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manually writing down each spec by hand</b>: not automation.</span><span class='qd'><b>Painting asset tags</b>: unrelated.</span><span class='qd'><b>Replacing all RAM</b>: a hardware task.</span>" },
{ id:"D4-148", domain:4, obj:"4.8", diff:"hard", q:"A poorly tested script run on production workstations causes browsers and the system to crash repeatedly. What is the BEST preventive practice?", options:["Run scripts only on Fridays","Test scripts in a non-production/sandbox environment and review code before mass deployment","Disable all scripting permanently","Increase the monitor brightness"], answer:1, explain:"<strong>Test scripts in a non-production/sandbox environment and review code before mass deployment</strong> is correct because testing first prevents widespread crashes and unintended effects.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Run scripts only on Fridays</b>: timing does not prevent bugs.</span><span class='qd'><b>Disable all scripting permanently</b>: removes a valuable tool unnecessarily.</span><span class='qd'><b>Increase the monitor brightness</b>: irrelevant.</span>" },
{ id:"D4-149", domain:4, obj:"4.8", diff:"medium", q:"Which extension represents a JavaScript file?", options:[".js",".py",".sh",".bat"], answer:0, explain:"<strong>.js</strong> is correct because .js is the JavaScript file extension.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>.py</b>: Python.</span><span class='qd'><b>.sh</b>: shell script.</span><span class='qd'><b>.bat</b>: Windows batch.</span>" },
{ id:"D4-150", domain:4, obj:"4.9", diff:"easy", q:"Which protocol provides a full graphical remote desktop session to a Windows machine using TCP port 3389 by default?", options:["SSH","RDP","Telnet","FTP"], answer:1, explain:"<strong>RDP</strong> is correct because Remote Desktop Protocol provides graphical remote sessions on Windows, typically over port 3389.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SSH</b>: secure command-line access, not full GUI desktop by default.</span><span class='qd'><b>Telnet</b>: insecure text-based remote access.</span><span class='qd'><b>FTP</b>: file transfer, not remote desktop.</span>" },
{ id:"D4-151", domain:4, obj:"4.9", diff:"easy", q:"Which protocol provides secure, encrypted command-line remote access to a device?", options:["Telnet","SSH","VNC","RDP"], answer:1, explain:"<strong>SSH</strong> is correct because SSH provides encrypted remote command-line access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Telnet</b>: command-line but unencrypted.</span><span class='qd'><b>VNC</b>: a graphical remote desktop tool.</span><span class='qd'><b>RDP</b>: graphical remote desktop, not primarily command-line.</span>" },
{ id:"D4-152", domain:4, obj:"4.9", diff:"medium", q:"A technician wants to provide cross-platform graphical remote control of a desktop. Which tool is BEST suited?", options:["SSH","VNC","FTP","Telnet"], answer:1, explain:"<strong>VNC</strong> is correct because VNC offers cross-platform graphical remote desktop control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SSH</b>: command-line focused.</span><span class='qd'><b>FTP</b>: file transfer only.</span><span class='qd'><b>Telnet</b>: text-based and unencrypted.</span>" },
{ id:"D4-153", domain:4, obj:"4.9", diff:"medium", q:"What does RMM software allow IT providers to do?", options:["Only transfer files","Remotely monitor and manage many endpoints, including patches, alerts, and maintenance","Replace physical hardware","Encrypt only local drives"], answer:1, explain:"<strong>Remotely monitor and manage many endpoints, including patches, alerts, and maintenance</strong> is correct because RMM (remote monitoring and management) centrally manages multiple systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only transfer files</b>: RMM does far more than file transfer.</span><span class='qd'><b>Replace physical hardware</b>: a physical task.</span><span class='qd'><b>Encrypt only local drives</b>: not the defining function.</span>" },
{ id:"D4-154", domain:4, obj:"4.9", diff:"hard", q:"A Windows user needs a technician to view and control their screen with the user's consent, using a built-in tool. Which is the BEST choice?", options:["FTP","Quick Assist / MSRA (Microsoft Remote Assistance)","Telnet","SSH"], answer:1, explain:"<strong>Quick Assist / MSRA (Microsoft Remote Assistance)</strong> is correct because these built-in Windows tools let a helper view and control a user's screen with consent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FTP</b>: only transfers files.</span><span class='qd'><b>Telnet</b>: text-based, unencrypted, no screen sharing.</span><span class='qd'><b>SSH</b>: command-line access, not interactive screen assistance.</span>" },
{ id:"D4-155", domain:4, obj:"4.9", diff:"hard", q:"When enabling RDP for remote administration, which security consideration is MOST important?", options:["Leaving it open to the entire internet for convenience","Restricting access (e.g., VPN, strong authentication, limited users) and avoiding direct exposure to the internet","Disabling all authentication","Using the default password on all accounts"], answer:1, explain:"<strong>Restricting access (e.g., VPN, strong authentication, limited users) and avoiding direct exposure to the internet</strong> is correct because exposed RDP is a major attack target, so access must be tightly controlled.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Leaving it open to the entire internet for convenience</b>: a severe security risk.</span><span class='qd'><b>Disabling all authentication</b>: removes a critical protection.</span><span class='qd'><b>Using the default password on all accounts</b>: easily exploited.</span>" }
);
